<?php
namespace App\Domain\Equipment;use InvalidArgumentException;
final class EquipmentItemFamily{const SWORD='sword';const AXE='axe';const DAGGER='dagger';const BOW='bow';const STAFF='staff';const SPEAR='spear';const WAND='wand';const SHIELD='shield';const FOCUS='focus';const GRIMOIRE='grimoire';const ORB='orb';private const WEAPONS=[self::SWORD,self::AXE,self::DAGGER,self::BOW,self::STAFF,self::SPEAR,self::WAND];private const SUPPORTS=[self::SHIELD,self::FOCUS,self::GRIMOIRE,self::ORB];public static function all(){return array_merge(self::WEAPONS,self::SUPPORTS);}public static function labels(){return[self::SWORD=>'Espada',self::AXE=>'Hacha',self::DAGGER=>'Daga',self::BOW=>'Arco',self::STAFF=>'Baston',self::SPEAR=>'Lanza',self::WAND=>'Varita',self::SHIELD=>'Escudo',self::FOCUS=>'Foco',self::GRIMOIRE=>'Grimorio',self::ORB=>'Orbe'];}public static function isWeapon($family){return in_array($family,self::WEAPONS,true);}public static function isOffHandSupport($family){return in_array($family,self::SUPPORTS,true);}public static function assertValid($family){if(!is_string($family)||!in_array($family,self::all(),true))throw new InvalidArgumentException('Familia de equipamiento no valida.');return$family;}private function __construct(){}}
